      if (contentType?.startsWith('image/')) {
        return {
          type: 'image',
          content: URL.createObjectURL(await response.blob()),
        };
      }

      return response.json();
    }

    return {
      listWorkspace,
      previewFile,
    };
  }, [api.baseUrl, api.authHeader]);
}

